module top_module(
    input clk,
    input load,
    input [3:0] in,
    output [3:0] out
);reg [3:0] obf_reg_out;

    always @(posedge clk) begin
        if (load) begin
            obf_reg_out <= in;
        end else begin
            obf_reg_out <= {obf_reg_out[2:0], 1'b0};
        end
    end

    assign out = obf_reg_out;

endmodule
